import Foundation

let swiftDevelopers: Set = ["Alice", "Bob", "Charlie", "Diana"]
let iOSDevelopers: Set = ["Charlie", "Diana", "Eve", "Frank"]

// Set operations
let allDevelopers = swiftDevelopers.union(iOSDevelopers)
let fullStackDevelopers = swiftDevelopers.intersection(iOSDevelopers)
let swiftOnly = swiftDevelopers.subtracting(iOSDevelopers)
let eitherNotBoth = swiftDevelopers.symmetricDifference(iOSDevelopers)

print("All developers: \(allDevelopers.sorted())")
print("Full-stack: \(fullStackDevelopers.sorted())")
print("Swift only: \(swiftOnly.sorted())")
print("Either not both: \(eitherNotBoth.sorted())")

// Membership
let aliceOnly: Set = ["Alice"]
print("Alice is subset: \(aliceOnly.isSubset(of: swiftDevelopers))")
print("Disjoint: \(swiftDevelopers.isDisjoint(with: ["Zoe"]))")
